  def search(conn, params) do
    search_term = Map.get(params, "search", "")
    min_price = Map.get(params, "min_price")
    max_price = Map.get(params, "max_price")
    category = Map.get(params, "category")
    in_stock = Map.get(params, "in_stock")
    sort_by = Map.get(params, "sort_by", "name")
    order = Map.get(params, "order", "asc")

    query = build_search_query(search_term, min_price, max_price, category, in_stock, sort_by, order)
    
    products = Repo.all(query)
    
    json(conn, %{products: products, count: length(products)})
  end

  defp build_search_query(search_term, min_price, max_price, category, in_stock, sort_by, order) do
    query = from(p in Product)

    query = if search_term != "" do
      from(p in query, where: fragment("name LIKE ?", ^"%#{search_term}%"))
    else
      query
    end

    query = if min_price do
      from(p in query, where: fragment("price >= ?", ^min_price))
    else
      query
    end

    query = if max_price do
      from(p in query, where: fragment("price <= ?", ^max_price))
    else
      query
    end

    query = if category do
      from(p in query, where: fragment("category = ?", ^category))
    else
      query
    end

    query = if in_stock do
      from(p in query, where: fragment("stock_quantity > 0"))
    else
      query
    end

    query = apply_sorting(query, sort_by, order)

    query
  end

  defp apply_sorting(query, sort_by, order) do
    order_direction = if order == "desc", do: :desc, else: :asc
    
    case sort_by do
      "price" ->
        from(p in query, order_by: [{^order_direction, p.price}])
      "created_at" ->
        from(p in query, order_by: [{^order_direction, p.inserted_at}])
      "stock" ->
        from(p in query, order_by: [{^order_direction, fragment("stock_quantity")}])
      _ ->
        from(p in query, order_by: [{^order_direction, p.name}])
    end
  end

  def advanced_search(conn, params) do
    search_term = Map.get(params, "search", "")
    fields = Map.get(params, "fields", ["name", "description"])
    
    query = build_multi_field_search(search_term, fields)
    products = Repo.all(query)
    
    json(conn, %{products: products, count: length(products)})
  end

  defp build_multi_field_search(search_term, fields) when search_term != "" do
    conditions = Enum.map(fields, fn field ->
      case field do
        "name" -> dynamic([p], fragment("name LIKE ?", ^"%#{search_term}%"))
        "description" -> dynamic([p], fragment("description LIKE ?", ^"%#{search_term}%"))
        "sku" -> dynamic([p], fragment("sku LIKE ?", ^"%#{search_term}%"))
        _ -> dynamic([p], fragment("name LIKE ?", ^"%#{search_term}%"))
      end
    end)

    combined_condition = Enum.reduce(conditions, fn condition, acc ->
      dynamic([], ^acc or ^condition)
    end)

    from(p in Product, where: ^combined_condition)
  end

  defp build_multi_field_search(_search_term, _fields) do
    from(p in Product)
  end

  def fuzzy_search(conn, %{"search" => search_term} = params) do
    limit = Map.get(params, "limit", "20") |> String.to_integer()
    
    query = from(p in Product,
      where: fragment("LOWER(name) LIKE LOWER(?)", ^"%#{search_term}%"),
      or_where: fragment("SOUNDEX(name) = SOUNDEX(?)", ^search_term),
      limit: ^limit
    )
    
    products = Repo.all(query)
    
    json(conn, %{products: products})
  end

  def full_text_search(conn, %{"search" => search_term}) do
    query = from(p in Product,
      where: fragment("MATCH(name, description) AGAINST(? IN BOOLEAN MODE)", ^search_term),
      order_by: fragment("MATCH(name, description) AGAINST(? IN BOOLEAN MODE) DESC", ^search_term)
    )
    
    products = Repo.all(query)
    
    json(conn, %{products: products, count: length(products)})
  end

  def search_with_pagination(conn, params) do
    search_term = Map.get(params, "search", "")
    page = Map.get(params, "page", "1") |> String.to_integer()
    per_page = Map.get(params, "per_page", "20") |> String.to_integer()
    
    offset = (page - 1) * per_page
    
    query = from(p in Product,
      where: fragment("name LIKE ?", ^"%#{search_term}%"),
      limit: ^per_page,
      offset: ^offset
    )
    
    count_query = from(p in Product,
      where: fragment("name LIKE ?", ^"%#{search_term}%"),
      select: count(p.id)
    )
    
    products = Repo.all(query)
    total_count = Repo.one(count_query)
    
    json(conn, %{
      products: products,
      page: page,
      per_page: per_page,
      total_count: total_count,
      total_pages: ceil(total_count / per_page)
    })
  end

  def search_by_tags(conn, %{"tags" => tags}) do
    tag_list = String.split(tags, ",")
    
    query = from(p in Product,
      where: fragment("EXISTS (SELECT 1 FROM unnest(tags) tag WHERE tag = ANY(?))", ^tag_list)
    )
    
    products = Repo.all(query)
    
    json(conn, %{products: products})
  end

  def autocomplete(conn, %{"q" => query_term}) do
    query = from(p in Product,
      where: fragment("name ILIKE ?", ^"#{query_term}%"),
      select: p.name,
      distinct: true,
      limit: 10
    )
    
    suggestions = Repo.all(query)
    
    json(conn, %{suggestions: suggestions})
  end
